import { ensureSchema } from "./schema.mjs";

export async function createShipment(client, data) {
  await ensureSchema(client);
  const doc = { ...data };
  await client.query('INSERT INTO shipments (shipment_id, order_id, doc) VALUES ($1, $2, $3) RETURNING doc', [doc.shipmentId, doc.orderId, JSON.stringify(doc)]);
  return doc;
}

export async function getShipment(client, shipmentId) {
  const res = await client.query('SELECT doc FROM shipments WHERE shipment_id = $1', [shipmentId]);
  return res.rows[0]?.doc || null;
}

export async function getShipmentsByOrder(client, orderId) {
  const res = await client.query('SELECT doc FROM shipments WHERE order_id = $1', [orderId]);
  return res.rows.map(r => r.doc);
}
